dot(D);
dot(G);
dot(F);
dot(O);
fill((-2,1.85)..C--G..cycle,white);
fill((2,1.85)..D--F..cycle,white);
label("$A$",A,W);
label("$B$",B,E);
label("$C$",C,SW);
label("$D$",D,SE);
